```tsx web/breeze/components/OfferPage/ErrorPages/ExpiredOfferErrorPage.tsx
import { BodyL, BodyS, Box, Button } from '@otovo/rainbow';
import { useRouter } from 'next/router';
import { useState } from 'react';
import { FormattedMessage as T, useIntl } from 'react-intl';

import Alert from '@otovo/shared/components/Alert/Alert';
import ErrorStatusPage from '@otovo/shared/components/ErrorStatusPage/ErrorStatusPage';
import ClockReverseTimeSVG from '@otovo/shared/images/icons/Clock/clock-reverse-time.svg';
import DocumentsFlyingAwayCustomer from '@otovo/shared/images/illustrations/2022/DocumentsFlyingAwayCustomer';
import { logUIEvent } from '@otovo/shared/lib/analytics/analytics';
import useSWRMutation from 'swr/mutation';

import { FetchOfferError } from '../../useOffer';
import { SELF_SERIVCE_AGENT_EMAIL } from '../constants';
import AgentInfo from '../HeaderSection/AgentInfo';
import m from '../messages';

type Props = {
  error: FetchOfferError;
  offerId: string;
};

async function sendRequest(url: string) {
  const response = await fetch(url, {
    method: 'post',
    headers: { 'content-type': 'application/json' },
  });
  if (!response.ok) {
    throw new Error(response.statusText);
  }
  return response.json();
}

type UpdateExpiryResponseType = {
  offer_id: string;
  offer_url: string;
};

const ExpiredOfferErrorPage = ({ error, offerId }: Props) => {
  const intl = useIntl();
  const {
    agent,
    can_be_updated: canBeUpdated,
    has_discount: hasDiscount,
    has_renewable_discount: hasRenewableDiscount,
  } = error.info;
  const router = useRouter();

  const [updateFailed, setUpdateFailed] = useState(false);

  const { trigger, isMutating } = useSWRMutation(
    `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/solar_offer/${offerId}/update_expiry/`,
    sendRequest,
    {
      onSuccess: (data: UpdateExpiryResponseType) => {
        router.push(data.offer_url);
      },
      onError: () => {
        setUpdateFailed(true);
      },
    },
  );

  const showUpdateExpiry = canBeUpdated && !updateFailed;
  const showDiscountLostWarning = hasDiscount && !hasRenewableDiscount;

  const renderExpiryText = () => {
    if (showUpdateExpiry) {
      return showDiscountLostWarning ? (
        <>
          <BodyL>
            <T {...m.offerExpiredContactYourAgentOrUpdate} />
          </BodyL>
          <BodyS mt={{ s: 2, m: 4 }}>
            <T {...m.renewedOfferWillLoseDiscount} />
          </BodyS>
        </>
      ) : (
        <T {...m.offerExpiredContactYourAgentOrUpdate} />
      );
    }
    return <T {...m.offerExpiredContactYourAgent} />;
  };

  return (
    <ErrorStatusPage
      status={error.status}
      headTitle={intl.formatMessage(m.offerExpiredHeader)}
      title={<T {...m.offerExpiredHeader} />}
      illustration={<DocumentsFlyingAwayCustomer showClock />}
    >
      <Box mb="4">{renderExpiryText()}</Box>
      {updateFailed && (
        <Alert variant="error">
          <T {...m.offerExpiredUpdateFailed} />
        </Alert>
      )}

      {showUpdateExpiry && (
        <Button
          loading={isMutating}
          variant="peach"
          color="text_heading"
          px={{ s: '1em', m2: '5em' }}
          py="1em"
          my="1em"
          onClick={() => {
            logUIEvent({
              action: 'User clicked the update offer button',
            });
            trigger();
          }}
          icon={<ClockReverseTimeSVG />}
        >
          <T {...m.offerExpiredUpdateMyOfferButtonLabel} />
        </Button>
      )}
      {agent && agent.email !== SELF_SERIVCE_AGENT_EMAIL && (
        <AgentInfo agent={agent} />
      )}
    </ErrorStatusPage>
  );
};

export { ExpiredOfferErrorPage };
```



I need to create a button that will re-create the offer (essentially the `showUpdateExpiry && <button>...</button>` part of the existing page.)

I want to separate logic and layout so that this file exports two components: `ExpiredOfferErrorPage` and `RecreateExpiredOfferButton`. If you think it's better to export a hook and implement the button myself, I'm open to that as well.
I'll help you separate this into a reusable button component (or hook). Here's how we can refactor this:

```tsx
// hooks/useRecreateExpiredOffer.ts
import { useState } from 'react';
import { useRouter } from 'next/router';
import useSWRMutation from 'swr/mutation';
import { logUIEvent } from '@otovo/shared/lib/analytics/analytics';

async function sendRequest(url: string) {
  const response = await fetch(url, {
    method: 'post',
    headers: { 'content-type': 'application/json' },
  });
  if (!response.ok) {
    throw new Error(response.statusText);
  }
  return response.json();
}

type UpdateExpiryResponseType = {
  offer_id: string;
  offer_url: string;
};

export function useRecreateExpiredOffer(offerId: string) {
  const router = useRouter();
  const [updateFailed, setUpdateFailed] = useState(false);

  const { trigger, isMutating } = useSWRMutation(
    `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/solar_offer/${offerId}/update_expiry/`,
    sendRequest,
    {
      onSuccess: (data: UpdateExpiryResponseType) => {
        router.push(data.offer_url);
      },
      onError: () => {
        setUpdateFailed(true);
      },
    },
  );

  const handleRecreateOffer = () => {
    logUIEvent({
      action: 'User clicked the update offer button',
    });
    trigger();
  };

  return {
    updateFailed,
    isLoading: isMutating,
    recreateOffer: handleRecreateOffer,
  };
}

// components/RecreateExpiredOfferButton.tsx
import { Button } from '@otovo/rainbow';
import { FormattedMessage as T } from 'react-intl';
import ClockReverseTimeSVG from '@otovo/shared/images/icons/Clock/clock-reverse-time.svg';
import m from '../messages';

type Props = {
  loading: boolean;
  onClick: () => void;
};

export function RecreateExpiredOfferButton({ loading, onClick }: Props) {
  return (
    <Button
      loading={loading}
      variant="peach"
      color="text_heading"
      px={{ s: '1em', m2: '5em' }}
      py="1em"
      my="1em"
      onClick={onClick}
      icon={<ClockReverseTimeSVG />}
    >
      <T {...m.offerExpiredUpdateMyOfferButtonLabel} />
    </Button>
  );
}

// ExpiredOfferErrorPage.tsx (simplified)
export function ExpiredOfferErrorPage({ error, offerId }: Props) {
  const intl = useIntl();
  const {
    agent,
    can_be_updated: canBeUpdated,
    has_discount: hasDiscount,
    has_renewable_discount: hasRenewableDiscount,
  } = error.info;

  const { updateFailed, isLoading, recreateOffer } = useRecreateExpiredOffer(offerId);

  const showUpdateExpiry = canBeUpdated && !updateFailed;
  const showDiscountLostWarning = hasDiscount && !hasRenewableDiscount;

  // ... rest of the render logic

  return (
    <ErrorStatusPage
      status={error.status}
      headTitle={intl.formatMessage(m.offerExpiredHeader)}
      title={<T {...m.offerExpiredHeader} />}
      illustration={<DocumentsFlyingAwayCustomer showClock />}
    >
      <Box mb="4">{renderExpiryText()}</Box>
      {updateFailed && (
        <Alert variant="error">
          <T {...m.offerExpiredUpdateFailed} />
        </Alert>
      )}

      {showUpdateExpiry && (
        <RecreateExpiredOfferButton
          loading={isLoading}
          onClick={recreateOffer}
        />
      )}

      {agent && agent.email !== SELF_SERIVCE_AGENT_EMAIL && (
        <AgentInfo agent={agent} />
      )}
    </ErrorStatusPage>
  );
}
```

This refactoring:

1. Extracts all the logic for recreating an offer into a custom hook (`useRecreateExpiredOffer`)
2. Creates a separate presentational component for the button (`RecreateExpiredOfferButton`)
3. Simplifies the main page component

You can now use either the hook or the button component independently in other parts of your application. The hook approach gives you more flexibility as you can implement your own UI while reusing the logic, while the component approach gives you a ready-to-use button with consistent styling.

You could use them like this:

```tsx
// Using the hook
const { isLoading, updateFailed, recreateOffer } = useRecreateExpiredOffer(offerId);

// Using the component
<RecreateExpiredOfferButton loading={isLoading} onClick={recreateOffer} />
```

This separation of concerns makes the code more maintainable and reusable, while keeping the same functionality.
